import React, { useEffect, useState } from 'react';
import api from '../api'; 
import PatientCard from './PatientCard'; // Siguroha nga walay { }

const PatientList = () => {
    const [patients, setPatients] = useState([]);

    useEffect(() => {
        api.get('patients/')
            .then((res: any) => setPatients(res.data)) // Butangan og : any
            .catch((err: any) => console.error("Error:", err)); // Butangan og : any
    }, []);

    return (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {patients.map((p: any) => (
                <PatientCard key={p.patient_id} patient={p} />
            ))}
        </div>
    );
};

export default PatientList;
